#include <vector>
#include <climits>
#include <algorithm>
using namespace std;

typedef long long ll;
const ll INF = 1e18;

struct SegmentTree {
    int n;
    vector<ll> tree;
    bool isMax;

    SegmentTree(vector<ll>& arr, bool type) {
        isMax = type;
        n = arr.size();
        tree.resize(4*n);
        if (n > 0) {
            build(1, 0, n-1, arr);
        }
    }

    void build(int node, int l, int r, vector<ll>& arr) {
        if (l == r) {
            tree[node] = arr[l];
            return;
        }
        int mid = (l + r) / 2;
        build(2*node, l, mid, arr);
        build(2*node+1, mid+1, r, arr);
        if (isMax) {
            tree[node] = max(tree[2*node], tree[2*node+1]);
        } else {
            tree[node] = min(tree[2*node], tree[2*node+1]);
        }
    }

    ll query(int node, int l, int r, int ql, int qr) {
        if (ql > qr) {
            if (isMax) return -INF;
            else return INF;
        }
        if (qr < l || r < ql) {
            if (isMax) return -INF;
            else return INF;
        }
        if (ql <= l && r <= qr) {
            return tree[node];
        }
        int mid = (l + r) / 2;
        ll left_res = query(2*node, l, mid, ql, qr);
        ll right_res = query(2*node+1, mid+1, r, ql, qr);
        if (isMax) {
            if (left_res == -INF && right_res == -INF) return -INF;
            else if (left_res == -INF) return right_res;
            else if (right_res == -INF) return left_res;
            else return max(left_res, right_res);
        } else {
            if (left_res == INF && right_res == INF) return INF;
            else if (left_res == INF) return right_res;
            else if (right_res == INF) return left_res;
            else return min(left_res, right_res);
        }
    }

    ll range_query(int ql, int qr) {
        if (ql > qr) {
            if (isMax) return -INF;
            else return INF;
        }
        return query(1, 0, n-1, ql, qr);
    }
};

ll solve(vector<long long> nums) {
    int n = nums.size();
    vector<ll> P;
    P.push_back(0);
    for (int i = 0; i < n; i++) {
        P.push_back(P.back() + nums[i]);
    }
    int sz = n+1;

    vector<int> L(n, 0);
    L[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i-1]) {
            L[i] = L[i-1];
        } else {
            L[i] = i;
        }
    }

    vector<int> R2(n, 0);
    R2[n-1] = n-1;
    for (int i = n-2; i >= 0; i--) {
        if (nums[i] < nums[i+1]) {
            R2[i] = R2[i+1];
        } else {
            R2[i] = i;
        }
    }

    vector<int> decR(n, 0);
    decR[n-1] = n-1;
    for (int i = n-2; i >= 0; i--) {
        if (nums[i] > nums[i+1]) {
            decR[i] = decR[i+1];
        } else {
            decR[i] = i;
        }
    }

    SegmentTree st_min(P, false);
    SegmentTree st_max(P, true);

    vector<ll> minL(n, INF);
    for (int p = 1; p < n; p++) {
        int low = L[p];
        int high = p-1;
        if (low <= high) {
            minL[p] = st_min.range_query(low, high);
        }
    }

    vector<ll> M(n, -INF);
    for (int q = 0; q < n; q++) {
        if (q+1 <= R2[q]) {
            int left_p = q+2;
            int right_p = R2[q] + 1;
            if (left_p <= right_p && right_p < sz) {
                M[q] = st_max.range_query(left_p, right_p);
            }
        }
    }

    SegmentTree st_M(M, true);

    ll ans = -INF;
    for (int p = 1; p < n-1; p++) {
        if (minL[p] == INF) continue;
        if (p+1 <= decR[p]) {
            ll bestM = st_M.range_query(p+1, decR[p]);
            if (bestM == -INF) continue;
            ll candidate = bestM - minL[p];
            if (candidate > ans) {
                ans = candidate;
            }
        }
    }

    return ans;
}
