        if (nums[i] < nums[i + 1]) {
            right_inc[i] = right_inc[i + 1];
        } else {
            right_inc[i] = i;
        }
    }

    int len_Q = Q.size();
    int k = (len_Q == 0) ? 0 : (log2(len_Q) + 1);
    vector<vector<long long>> st_max_Q(len_Q, vector<long long>(k, LLONG_MIN));
    vector<vector<long long>> st_min_Q(len_Q, vector<long long>(k, LLONG_MAX));

    for (int i = 0; i < len_Q; i++) {
        st_max_Q[i][0] = Q[i];
        st_min_Q[i][0] = Q[i];
    }

    for (int j = 1; j < k; j++) {
        int step = 1 << (j - 1);
        for (int i = 0; i + (1 << j) <= len_Q; i++) {
            st_max_Q[i][j] = max(st_max_Q[i][j - 1], st_max_Q[i + step][j - 1]);
            st_min_Q[i][j] = min(st_min_Q[i][j - 1], st_min_Q[i + step][j - 1]);
        }
    }

    auto query_max_sparse = [](const vector<vector<long long>>& st, int l, int r, int k) -> long long {
        if (l > r) return LLONG_MIN;
        int len = r - l + 1;
        if (len == 1) {
            return st[l][0];
        }
        int j = 31 - __builtin_clz(len);
        return max(st[l][j], st[r - (1 << j) + 1][j]);
    };

    auto query_min_sparse = [](const vector<vector<long long>>& st, int l, int r, int k) -> long long {
        if (l > r) return LLONG_MAX;
        int len = r - l + 1;
        if (len == 1) {
            return st[l][0];
        }
        int j = 31 - __builtin_clz(len);
        return min(st[l][j], st[r - (1 << j) + 1][j]);
    };

    vector<long long> M(n, LLONG_MIN);
    for (int j = 0; j < n - 1; j++) {
        if (nums[j] < nums[j + 1]) {
            int L_idx = j + 2;
            int R_idx = right_inc[j] + 1;
            if (L_idx <= R_idx && R_idx < len_Q) {
                M[j] = query_max_sparse(st_max_Q, L_idx, R_idx, k);
            } else if (L_idx < len_Q) {
                R_idx = min(R_idx, len_Q - 1);
                if (L_idx <= R_idx) {
