    for (int j = 1; j < k_M; j++) {
        int step = 1 << (j - 1);
        for (int i = 0; i + (1 << j) <= len_M; i++) {
            st_max_M[i][j] = max(st_max_M[i][j - 1], st_max_M[i + step][j - 1]);
        }
    }

    auto query_st_max_M = [&](int l, int r) -> long long {
        if (l > r) return LLONG_MIN;
        int len = r - l + 1;
        if (len == 1) {
            return st_max_M[l][0];
        }
        int j = 31 - __builtin_clz(len);
        return max(st_max_M[l][j], st_max_M[r - (1 << j) + 1][j]);
    };

    long long ans = LLONG_MIN;
    for (int p = 1; p < n - 1; p++) {
        if (nums[p - 1] < nums[p] && nums[p] > nums[p + 1]) {
            if (left_inc[p] <= p - 1) {
                int j0 = p + dec_len[p] - 1;
                int R_j = min(j0, n - 2);
                if (p + 1 <= R_j) {
                    long long max_val_j = query_st_max_M(p + 1, R_j);
