#include <vector>
#include <algorithm>
#include <climits>
using namespace std;

typedef long long LL;
const LL INF = 1e18;

class SegmentTree {
public:
    vector<LL> tree;
    vector<LL> data;
    int n;
    bool is_min;
    SegmentTree(vector<LL> data, bool is_min) : data(data), is_min(is_min) {
        n = data.size();
        tree.resize(4 * n);
        build(0, n-1, 0);
    }

    void build(int l, int r, int idx) {
        if (l == r) {
            tree[idx] = data[l];
            return;
        }
        int mid = (l + r) / 2;
        build(l, mid, 2*idx+1);
        build(mid+1, r, 2*idx+2);
        if (is_min) {
            tree[idx] = min(tree[2*idx+1], tree[2*idx+2]);
        } else {
            tree[idx] = max(tree[2*idx+1], tree[2*idx+2]);
        }
    }

    LL query(int l, int r, int segl, int segr, int idx) {
        if (l > segr || r < segl) {
            if (is_min) return INF;
            else return -INF;
        }
        if (l <= segl && segr <= r) {
            return tree[idx];
        }
        int mid = (segl + segr) / 2;
        LL left_val = query(l, r, segl, mid, 2*idx+1);
        LL right_val = query(l, r, mid+1, segr, 2*idx+2);
        if (is_min) {
            return min(left_val, right_val);
        } else {
            return max(left_val, right_val);
        }
    }

    LL query(int l, int r) {
        if (l > r) {
            if (is_min) return INF;
            else return -INF;
        }
        return query(l, r, 0, n-1, 0);
    }
};

LL solve(vector<LL> nums) {
    int n = nums.size();
    vector<LL> prefix(n+1, 0);
    for (int i=1; i<=n; i++) {
        prefix[i] = prefix[i-1] + nums[i-1];
    }

    vector<int> left_inc(n, 0);
    left_inc[0] = 0;
    for (int i=1; i<n; i++) {
        if (nums[i] > nums[i-1]) {
            left_inc[i] = left_inc[i-1];
        } else {
            left_inc[i] = i;
        }
    }

    vector<int> left_bound_dec(n, 0);
    left_bound_dec[0] = 0;
    for (int i=1; i<n; i++) {
        if (nums[i] < nums[i-1]) {
            left_bound_dec[i] = left_bound_dec[i-1];
        } else {
            left_bound_dec[i] = i;
        }
    }

    vector<int> right_inc(n, 0);
    right_inc[n-1] = n-1;
    for (int i=n-2; i>=0; i--) {
        if (nums[i] < nums[i+1]) {
            right_inc[i] = right_inc[i+1];
        } else {
            right_inc[i] = i;
        }
    }

    SegmentTree st_min(prefix, true);
    SegmentTree st_max(prefix, false);

    vector<LL> M_peak(n, INF);
    for (int i=0; i<n; i++) {
        if (left_inc[i] <= i-1) {
            M_peak[i] = st_min.query(left_inc[i], i-1);
        }
    }

    vector<LL> R_arr(n, -INF);
    for (int i=0; i<n; i++) {
        int r_end = right_inc[i];
        int L_index = i+1;
        int R_index = r_end+1;
        R_index = min(R_index, n);
        if (L_index <= R_index) {
            R_arr[i] = st_max.query(L_index, R_index);
        }
    }

    SegmentTree st_peak_min(M_peak, true);

    LL ans = -INF;

    for (int q=2; q<n; q++) {
        int L_bound = left_bound_dec[q];
        int R_bound = q-1;
        if (L_bound > R_bound) continue;

        LL min_val_peak = st_peak_min.query(L_bound, R_bound);
        if (min_val_peak == INF) continue;
        if (R_arr[q] == -INF) continue;

        LL candidate = R_arr[q] - min_val_peak;
        if (candidate > ans) {
            ans = candidate;
        }
    }

    return ans;
}
```

### Explanation
1. **Prefix Sum Array**: The prefix array allows O(1) range sum queries by storing cumulative sums.
2. **Left/Right Segments**: The arrays `left_inc`, `left_bound_dec`, and `right_inc` help identify valid segments for the three parts of the subarray (increasing, decreasing, increasing).
3. **Segment Trees**: These trees enable efficient range queries (min and max) on the prefix sum array, crucial for handling large input sizes within feasible time complexity (O(log n) per query).
4. **M_peak and R_arr**: These arrays store precomputed values to determine the best starting (left) and ending (right) indices for maximizing the subarray sum.
5. **Iteration Over Valleys**: For each potential valley (end of the decreasing segment), the solution checks valid peaks (using precomputed min values) and combines them with the best right segment to compute the maximum subarray sum efficiently.

This approach efficiently narrows down the search space using precomputed segments and segment trees, ensuring optimal performance even for large inputs.
